import{_ as e,o as a,c as t,ak as _}from"./chunks/framework.BwREiRwV.js";const m=JSON.parse('{"title":"第二十章 一壶冷药","description":"","frontmatter":{},"headers":[],"relativePath":"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md","filePath":"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md"}'),r={name:"永恒道途/正文/第一卷-山门有路/第二十章-一壶冷药.md"};function o(n,p,s,c,i,d){return a(),t("div",null,[...p[0]||(p[0]=[_('<h1 id="第二十章-一壶冷药" tabindex="-1">第二十章 一壶冷药 <a class="header-anchor" href="#第二十章-一壶冷药" aria-label="Permalink to &quot;第二十章 一壶冷药&quot;">​</a></h1><p>剑峰在青云七峰最北。</p><p>陈玄寅时到峰脚时，天还没有亮。石阶顺山势没入夜色，两侧插满残旧剑碑，碑上剑痕纵横，有的细若发丝，有的深达数寸。山风穿过碑林，发出低沉呜鸣，仿佛许多柄看不见的剑在黑暗中同时震颤。</p><p>他没有急着触碰剑痕。</p><p>李清风昨日只让他寅时上峰，没有说这些剑碑能随意参悟。初来乍到，先守规矩比追一份不知属于谁的机缘重要。</p><p>石阶共有一千三百级。</p><p>走到一半时，陈玄胸口旧伤开始发紧。前日决位战强行施展青莲变式，右臂经脉又添新伤，医师让他休养半月，他却不愿拜师第一日便迟到。</p><p>最后一百级，他每一步都走得很慢。</p><p>跨上峰顶时，东方刚露出一线灰白。</p><p>剑峰比想象中简陋。三间木屋，一座练剑坪，一口老井，除此之外只有一株被风吹得向南倾斜的古松。没有成群侍从，也没有灵兽守门，练剑坪边甚至还晾着两件洗得发白的青衫。</p><p>李清风站在井边打水。</p><p>“迟了三息。”</p><p>陈玄看向天色：“弟子寅时前已到峰顶。”</p><p>“我说的是你在最后一级停了三息。”李清风把木桶提上井沿，“胸口疼？”</p><p>陈玄没有隐瞒：“旧伤未愈。”</p><p>“知道有伤还爬这么急，是觉得守时比根基重要？”</p><p>“弟子不想第一日迟到。”</p><p>李清风看了他一眼：“守时是让你提前算清自己的脚程，不是让你用伤换三息。明日起早一刻。”</p><p>“是。”</p><p>“先去东屋。”</p><p>陈玄原以为东屋是练功房，推门后却闻到浓郁药味。屋中放着一只青石药池，水汽氤氲，池边备着干净布巾和一套窄袖练功衣。</p><p>“药堂开的方子只能治表伤。”李清风将一包药粉倒进池中，“血煞伤过经脉，雷火又击中过同一条肩脉。先泡七日，七日后再握剑。”</p><p>陈玄一怔：“师父今日不试剑？”</p><p>“你在擂台上出了十几场，能看的我都看过。”</p><p>“弟子的青莲剑歌尚有许多问题。”</p><p>“所以更不急着看。”李清风道，“一个人刚学会走，便急着让我点评他如何跑，只会把原本会走的也忘掉。”</p><p>药池水温不高，浸入其中后，右臂经脉却渐渐发热。药力不像回脉草那般猛烈，只沿着细小暗伤缓慢渗透，疼痛也从尖锐变成了持续的酸胀。</p><p>陈玄闭目调息。</p><p>七日里，李清风果然没有让他碰剑。</p><p>卯时泡药，辰时沿剑峰缓步一周，午后抄录《青元剑诀》，夜里只运转最基础的《吐纳诀》。陈玄起初不明白为何要抄一部早已背熟的剑诀，抄到第三遍才发现，自己过去总把注意力放在行气图与三式剑招上，忽略了每一重末尾关于收势与养脉的短注。</p><p>“青元剑诀外门前三重并不残缺。”李清风看过他的抄本，“残的是历代注解。藏经阁无人教，许多人只知道如何出剑，不知道为何收剑。”</p><p>他递来一枚旧玉简。</p><p>玉简里不是更高深的剑法，而是剑峰数代修士留下的修炼心得。有人写凝锋时如何避免金火相冲，有人记录回云斩对肩肘的损耗，也有人只留下一句“剑去七分，三分归身”。</p><p>陈玄看到最后一句，停了很久。</p><p>他过去每次生死交手都习惯把所有后手压在最后一击，青莲剑歌尤其如此。一式之后灵力近空，若对手未败，他便再没有退路。</p><p>“师父，三分归身，是留力逃命？”</p><p>“也可以是留力出下一剑。”李清风道，“真正的杀招不是把自己一同杀进去。除非身后已没有人可退，否则永远给自己留一剑。”</p><p>第八日清晨，陈玄终于重新站上练剑坪。</p><p>“出剑。”李清风道。</p><p>陈玄拔出青锋剑，没有施展青莲剑歌，只按顺序走过青锋起、回云斩与落照归。三式结束，剑气卷起坪边落叶，在半空短暂聚成三瓣青光。</p><p>李清风看完，只说：“根基尚可，毛病很多。”</p><p>“请师父指点。”</p><p>“第一，脚步比剑快，说明你怕来不及；第二，三式都在找对手破绽，却没有一式敢逼对手犯错；第三，出剑总想一剑赚回本。”</p><p>陈玄心头一震。</p><p>前两点他能听懂，最后一句却像直接点中了这些年藏在骨子里的习惯。</p><p>他出身贫寒，灵石要算，丹药要省，连绿液也必须分出三分之一使用。久而久之，剑也被他当成了一桩不能亏本的买卖。每一剑若不能换来伤势、位置或灵力消耗，他便觉得浪费。</p><p>这种习惯让他擅长抓破绽，也让他的剑总带着急于得到回报的痕迹。</p><p>“剑道不是买卖。”李清风从地上拾起一根枯枝，“有些剑是逼路，有些剑是问路，有些剑出时便没打算伤人，却能让真正伤人的下一剑出现。”</p><p>枯枝随手刺出。</p><p>没有灵力，也不快。</p><p>陈玄却本能向左退了半步。退完才发现，左侧正是井沿与石壁夹角。若李清风手中还有第二剑，他已经无处可避。</p><p>“你看，这一刺没有赚到任何东西。”李清风收回枯枝，“只是让你自己走进了该去的位置。”</p><p>陈玄望着脚下，许久才抱拳：“弟子明白了。”</p><p>“明白得太早。”李清风把枯枝丢给他，“从今日起，一个月不准用真剑。每日一千刺，要求不在快，在落点相同。另加五百次空刺，剑尖不得触物，只练逼位。”</p><p>“是。”</p><p>第一日一千刺结束，陈玄右臂酸得抬不起来。</p><p>枯枝比青锋剑轻，没有剑身重量帮助稳定，手腕每一点偏移都会落在靶纸不同位置。最初一百刺散在拳头大小，五百刺后反而越练越偏。</p><p>李清风没有让他加练，只在日落时收走枯枝。</p><p>“累了还硬刺，练进去的是错。回去吃饭。”</p><p>饭是两碗清汤面，一碟盐水煮肉。</p><p>李清风做饭的手艺算不上好，面条粗细不一，肉也煮得有些老。陈玄却吃得很慢。青石村时父亲偶尔也会煮面，手艺同样不好，面汤总带着一股灶灰味。</p><p>“不合口？”李清风问。</p><p>“很好。”</p><p>“那便快吃。凉了伤胃。”</p><p>师徒二人没有谈剑，也没有谈大比。李清风问了些药园的事，陈玄便说凝露草如何开花，鲁老头如何用烟杆敲人。说到那半块灵谷饼时，李清风很轻地笑了一下。</p><p>“鲁九以前也是剑峰弟子。”</p><p>陈玄抬头。</p><p>“四十年前伤了右手，经脉尽断，不愿留在峰上看别人练剑，便去了药园。”李清风道，“他的烟杆里藏着一截断剑。你若有机会，可以问他；他若不说，便别再问。”</p><p>陈玄想起鲁老头少了半截的小指，也终于明白老人在黑风山那句“八人去，三人回”背后还有更多没有说出的往事。</p><p>第二日，靶纸上的刺痕缩到半个拳头。</p><p>第七日，千次落点只剩铜钱大小。</p><p>第十五日，陈玄开始练空刺。没有目标比有目标更难，他必须用第一剑迫使想象中的对手向左，再用第二剑封住后退，第三剑才真正触及咽喉。</p><p>李清风每日只看最后十次，从不替他把所有答案说完。</p><p>“师父，若对手第一步不向左呢？”</p><p>“那说明你第一剑没有让他觉得左边更安全。”</p><p>“如何让他觉得安全？”</p><p>“自己想。”</p><p>一个月后，陈玄重新握住青锋剑。</p><p>剑出得比从前慢了半分，剑路却更稳。青锋起不再急着伤人，而是封住右侧；回云斩也不再追逐对手身体，而是斩向他下一步必须经过的位置。</p><p>李清风以枯枝与他对剑。</p><p>前十招，陈玄一招未成。</p><p>第二十七招，他第一次让李清风向后退了半步。</p><p>代价是下一瞬，枯枝已经停在他喉前。</p><p>陈玄没有沮丧，反而笑了。</p><p>过去与师父对剑，他连对方为何站在那里都看不懂。如今至少有一剑，真正逼出了半步。</p><p>李清风收枝：“笑早了。明日目标是一整步。”</p><p>“是。”</p><p>入剑峰第二个月末，陈玄踏入炼气八层。</p><p>这次突破没有依赖掌天瓶催出的药草。内门月俸中的灵米、养气丹，剑峰聚灵阵与更准确的行气指点共同补足了修炼所需。四属性灵根依旧让吸纳速度缓慢，却不再有大量灵力浪费在错误路线里。</p><p>李清风验过修为，只说：“境界比我预计早了五日。今日少刺两百，稳境。”</p><p>陈玄原以为这便是夸奖，晚饭时才发现碗里比平日多了一只卤鸡腿。</p><p>他没有揭穿，只把鸡腿一分为二，一半夹回师父碗中。</p><p>李清风看了他一眼，没再夹回来。</p><p>第三个月，陈玄开始在瀑布下练剑。</p><p>水流压住肩背，任何多余动作都会让身体失衡。他从最初只能站十息，到后来能在水下完整走完三式。青莲剑歌也被拆开重练，不再追求三瓣同时爆发，而是让每一瓣都承担不同作用。</p><p>第一瓣逼位，第二瓣封招，第三瓣杀敌。</p><p>这样一来，威力看似不如大比时惊人，灵力消耗却少了近四成。一式之后，他终于还能保留第二道青元剑气。</p><p>第四个月初，宗门下发七宗会武名册。</p><p>会武将在半年后举行，青云宗只有五个名额。参与者限定二十二岁以下、筑基初期以下，既有新晋内门，也有各峰修行多年的年轻弟子。</p><p>李清风把名册放在桌上：“想去？”</p><p>“想。”</p><p>“为什么？”</p><p>“宗内能看见的剑，我已经看过一些。七宗的修士如何用刀、用符、炼体，我想亲眼看看。”陈玄顿了顿，“血魔子也可能去。”</p><p>李清风目光微沉：“你现在杀不了他。”</p><p>“弟子知道。”</p><p>“知道还去？”</p><p>“见到强敌不等于一定要当场杀。先看清他的功法、习惯与弱点，也是以后活下来的准备。”</p><p>李清风点了点头：“这个答案可以。但名额不是我给你。半年后峰内选拔，你自己争。”</p><p>“是。”</p><p>夜里，陈玄练完最后一千刺，回到自己的木屋。</p><p>掌天瓶安静藏在储物袋最深处。李清风从未问过他为何总能拿出年份稳定的药草，也没有以金丹神识搜查弟子隐私。</p><p>每个人都有秘密。</p><p>真正的师长不是替弟子夺走所有秘密，而是教他即使离开秘密，也知道如何站稳。</p><p>窗外，李清风正在井边擦剑。月光照在无鞘古剑上，也照亮桌上那只给陈玄留着的药壶。</p><p>师恩不是一句护你一世。</p><p>是有人明知你终究要独自走远，仍愿意在你尚且稚嫩时，把走路的方法一遍遍教给你。</p><p>陈玄取出枯枝，面向夜色，再刺一剑。</p><p>这一剑不快，却比昨日更直。</p><p>（第二十章完）</p>',119)])])}const f=e(r,[["render",o]]);export{m as __pageData,f as default};
